// Dijkstra's algorithm implementation
// Finds shortest path from a source node to all other nodes
// The weights depend on whether the traversal is "empty" (no apple) or "loaded" (with apple)
func dijkstra(n int, adj map[int][]Edge, startNode int, isLoaded bool) []int64 {
	distances := make([]int64, n)
	for i := range distances {
		distances[i] = math.MaxInt64
	}

	distances[startNode] = 0

	// Priority queue stores {distance, node}
	pq := make(PriorityQueue, 0)
	heap.Push(&pq, Item{value: startNode, priority: 0})

	for pq.Len() > 0 {
		item := heap.Pop(&pq).(Item)
		u := item.value
		d := item.priority

		if d > distances[u] {
			continue
		}

		for _, edge := range adj[u] {
			v := edge.to
			var weight int64

			if isLoaded {
				// Loaded travel: cost * tax
				weight = edge.cost * edge.tax
			} else {
				// Empty travel: cost
				weight = edge.cost
			}

			if distances[u] != math.MaxInt64 && distances[u]+weight < distances[v] {
				distances[v] = distances[u] + weight
				heap.Push(&pq, Item{value: v, priority: distances[v]})
			}
		}
	}
	return distances
}

// --- Heap implementation for Dijkstra's ---
import "container/heap"

type Item struct {
	value    int // The node index
	priority int64 // The distance
	index    int // The index in the heap array
}

type PriorityQueue []Item

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	// We want Pop to give us the item with the *smallest* priority (distance)
	return pq[i].priority < pq[j].priority
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
	pq[i].index = i
	pq[j].index = j
}

func (pq *PriorityQueue) Push(x interface{}) {
	n := len(*pq)
	item := x.(Item)
	item.index = n
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	item.index = -1 // for safety
	*pq = old[0 : n-1]
	return item
}

// solve is the main function implementing the logic
func solve(n int64, prices []int64, roads [][]int64) []int64 {
	N := int(n)

	// 1. Build adjacency list for the graph
	adj := make(map[int][]Edge)
	for _, road := range roads {
		u := int(road[0])
		v := int(road[1])
		cost := road[2]
		tax := road[3]

		// Bidirectional roads
		edgeUV := Edge{to: v, cost: cost, tax: tax}
		edgeVU := Edge{to: u, cost: cost, tax: tax}

		adj[u] = append(adj[u], edgeUV)
		adj[v] = append(adj[v], edgeVU)
	}

	// 2. Calculate shortest paths for empty and loaded travel.
	// We need:
	// D_empty[i][j]: shortest path cost from i to j without apple.
	// D_loaded[i][j]: shortest path cost from i to j with apple.

	// Since we are interested in paths *to* j from i (empty) and paths *back* from j to i (loaded),
	// it's easier to run Dijkstra's from *every* node.

	// D_empty[j] = shortest path cost from *some* node to j (used for going to j empty-handed)
	// D_loaded[j] = shortest path cost from j back to *some* node (used for returning to i loaded)

	// Let's precalculate shortest paths from every node i:
	// dist_empty[i][j]: shortest path cost from i to j when empty
	// dist_loaded[i][j]: shortest path cost from i to j when loaded

	distEmpty := make([][]int64, N)
	distLoaded := make([][]int64, N)

	for i := 0; i < N; i++ {
		// Calculate paths starting at i when empty
		distancesEmpty := dijkstra(N, adj, i, false)
		distEmpty[i] = distancesEmpty

		// Calculate paths starting at i when loaded
		distancesLoaded := dijkstra(N, adj, i, true)
		distLoaded[i] = distancesLoaded
	}

	ans := make([]int64, N)

	// 3. Calculate the minimum cost for each store i
	for i := 0; i < N; i++ {
		// Option 1: Buy directly at store i
		minCost := prices[i]

		// Option 2: Travel to store j, buy, and return to store i
		for j := 0; j < N; j++ {
			if i == j {
				continue
			}

			// Path: i (empty) -> j (empty travel)
			// Cost: distEmpty[i][j]
			costEmptyToJ := distEmpty[i][j]

			// Path: j (loaded) -> i (loaded travel)
			// Cost: distLoaded[j][i]
			costLoadedFromJ := distLoaded[j][i]

			// If either path is unreachable, skip
			if costEmptyToJ == math.MaxInt64 || costLoadedFromJ == math.MaxInt64 {
				continue
			}

			// Total cost = (Travel i->j empty) + (Buy at j) + (Travel j->i loaded)
			totalCost := costEmptyToJ + prices[j] + costLoadedFromJ

			if totalCost < minCost {
				minCost = totalCost
			}
		}
		ans[i] = minCost
	}

	return ans
}
